9	// listProjects handles GET /api/projects?include_archived=1.
10	func (a *API) listProjects(w http.ResponseWriter, r *http.Request) {
11		includeArchived := r.URL.Query().Get("include_archived") == "1"
12		projects, err := a.Svc.ListProjects(includeArchived)
13		if err != nil {
14			writeError(w, err)
15			return
16		}
17		if projects == nil {
18			projects = []service.Project{}
19		}
20		writeJSON(w, http.StatusOK, map[string]any{"projects": projects})
21	}
22	
23	// createProject handles POST /api/projects.
24	func (a *API) createProject(w http.ResponseWriter, r *http.Request) {
25		var body struct {
26			Name        string            `json:"name"`
27			Problem     string            `json:"problem"`
28			Priority    service.Priority  `json:"priority"`
29			Description *string           `json:"description"`
30			Color       *string           `json:"color"`
31		}
32		if err := decodeBody(r, &body); err != nil {
33			writeError(w, err)
34			return
35		}
36		p, err := a.Svc.CreateProject(service.CreateProjectInput{
37			Name:        body.Name,
38			Problem:     body.Problem,
39			Priority:    body.Priority,
40			Description: body.Description,
41			Color:       body.Color,
42		})
43		if err != nil {
44			writeError(w, err)
45			return
46		}
47		writeJSON(w, http.StatusCreated, p)
48	}
49	
50	// getProject handles GET /api/projects/{slug}.
51	func (a *API) getProject(w http.ResponseWriter, r *http.Request) {
52		slug := r.PathValue("slug")
53		detail, err := a.Svc.GetProject(slug)
54		if err != nil {
55			writeError(w, err)
56			return
57		}
58		writeJSON(w, http.StatusOK, detail)
59	}
