// CanvasUniverse renders the petboard "universe" — every project as a
// glowing thread on an infinite, pan-and-zoom canvas. This is task #8
// (basic version). Drag-to-reposition, filters, and the time-window
// slider come in task #9.
//
// Coordinate system:
//   - World coordinates are stable across zooms. X axis is time, with
//     1 world pixel ≈ BASE_PX_PER_DAY/86400 seconds at scale=1. Y axis
//     is project lane * LANE_HEIGHT, offset by HEADER_OFFSET.
//   - Stage scale + position transforms world → screen.
//
// Semantic zoom thresholds:
//   - scale < 0.4   → just threads + orbs, no labels
//   - 0.4 ≤ scale < 1.5 → project labels visible at start of each thread
//   - scale ≥ 1.5  → feature labels visible next to orbs

import { useEffect, useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { Stage, Layer, Line, Circle, Text, Group, Rect } from "react-konva";
import type Konva from "konva";
import type { Feature, Project, ProjectDetail, Status } from "../api/types";

// ----- layout constants ---------------------------------------------------

const BASE_PX_PER_DAY = 8; // world pixels per day at scale=1
const LANE_HEIGHT = 90;
const HEADER_OFFSET = 80;
const ORB_RADIUS = 6;

const STATUS_COLORS: Record<Status, string> = {
  backlog: "#a3a3a3",
  in_progress: "#fbbf24",
  done: "#34d399",
  dropped: "#525252",
};

const SECS_PER_DAY = 86400;

// ----- props -------------------------------------------------------------

export interface UniverseData {
  projects: Project[];
  // optional per-slug detail (features) when the parent has loaded them.
  details?: Record<string, ProjectDetail>;
}

interface Props {
  data: UniverseData;
  width: number;
  height: number;
}

// ----- main component ----------------------------------------------------

export default function CanvasUniverse({ data, width, height }: Props) {
  const stageRef = useRef<Konva.Stage>(null);
  const navigate = useNavigate();

  // current viewport transform
  const [scale, setScale] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });

  // current time tick — re-renders the now-line every minute
  const [now, setNow] = useState(() => Date.now() / 1000);
  useEffect(() => {
    const id = setInterval(() => setNow(Date.now() / 1000), 60_000);
    return () => clearInterval(id);
  }, []);

  // time origin — earliest project created_at, or now if no projects
  const tOrigin = useMemo(() => {
    if (!data.projects.length) return now;
    return Math.min(...data.projects.map((p) => p.created_at));
  }, [data.projects, now]);

  // helpers
  const xForTime = (t: number) =>
    ((t - tOrigin) / SECS_PER_DAY) * BASE_PX_PER_DAY;

  // lane assignments — auto by created_at order unless canvas_y set
  const lanes = useMemo(() => {
    const sorted = data.projects
      .slice()
      .sort((a, b) => a.created_at - b.created_at);
    return sorted.map((p, i) => ({
      project: p,
      y: p.canvas_y ?? HEADER_OFFSET + i * LANE_HEIGHT,
    }));
  }, [data.projects]);

  // ----- pan + zoom handlers --------------------------------------------

  const handleWheel = (e: Konva.KonvaEventObject<WheelEvent>) => {
    e.evt.preventDefault();
    const stage = stageRef.current;
    if (!stage) return;
    const oldScale = scale;
    const pointer = stage.getPointerPosition();
    if (!pointer) return;

    // zoom factor — slightly larger than typical so wheel feels responsive
    const scaleBy = 1.06;
    const direction = e.evt.deltaY > 0 ? -1 : 1;
    const newScale = clamp(
      direction > 0 ? oldScale * scaleBy : oldScale / scaleBy,
      0.05,
      8,
    );

    // keep the world point under the cursor anchored after zoom
    const mousePointTo = {
      x: (pointer.x - offset.x) / oldScale,
      y: (pointer.y - offset.y) / oldScale,
    };
    const newOffset = {
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    };
    setScale(newScale);
    setOffset(newOffset);
  };

  const handleDragEnd = (e: Konva.KonvaEventObject<DragEvent>) => {
    if (e.target === stageRef.current) {
      setOffset({ x: e.target.x(), y: e.target.y() });
    }
  };

  // fit-all button: compute bbox of all threads and fit
  const fitAll = () => {
    if (!data.projects.length) return;
    const xMin = 0;
    const xMax = xForTime(now) + 80;
    const yMin = HEADER_OFFSET - 40;
    const yMax = HEADER_OFFSET + lanes.length * LANE_HEIGHT;
    const w = xMax - xMin;
    const h = yMax - yMin;
    const padding = 60;
    const sx = (width - padding * 2) / w;
    const sy = (height - padding * 2) / h;
    const newScale = clamp(Math.min(sx, sy), 0.05, 4);
    setScale(newScale);
    setOffset({
      x: padding - xMin * newScale,
      y: padding - yMin * newScale,
    });
  };

  useEffect(() => {
    // initial fit when data first arrives
    if (data.projects.length > 0 && scale === 1 && offset.x === 0 && offset.y === 0) {
      fitAll();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [data.projects.length, width, height]);

  // semantic zoom flags
  const showProjectLabels = scale >= 0.4;
  const showFeatureLabels = scale >= 1.5;

  return (
    <div className="relative w-full h-full bg-neutral-950">
      <Stage
        ref={stageRef}
        width={width}
        height={height}
        draggable
        x={offset.x}
        y={offset.y}
        scaleX={scale}
        scaleY={scale}
        onWheel={handleWheel}
        onDragEnd={handleDragEnd}
      >
        {/* Background grid */}
        <Layer listening={false}>
          <BackgroundGrid
            width={width}
            height={height}
            scale={scale}
            offset={offset}
          />
        </Layer>

        {/* Project threads + orbs */}
        <Layer>
          {lanes.map(({ project, y }) => (
            <ProjectThread
              key={project.id}
              project={project}
              y={y}
              now={now}
              xForTime={xForTime}
              detail={data.details?.[project.slug]}
              showLabel={showProjectLabels}
              showFeatureLabels={showFeatureLabels}
              scale={scale}
              onLabelClick={() => navigate(`/p/${project.slug}`)}
            />
          ))}

          {/* Now line */}
          <NowLine
            x={xForTime(now)}
            yTop={HEADER_OFFSET - 40}
            yBottom={HEADER_OFFSET + Math.max(lanes.length, 1) * LANE_HEIGHT}
          />
        </Layer>
      </Stage>

      {/* Floating UI overlays */}
      <div className="absolute top-3 right-3 flex gap-2">
        <button
          type="button"
          onClick={fitAll}
          className="px-3 py-1 text-xs rounded border border-neutral-700 bg-neutral-900/80 backdrop-blur hover:bg-neutral-800"
          title="fit all to view"
        >
          fit
        </button>
        <button
          type="button"
          onClick={() => setScale((s) => clamp(s * 1.5, 0.05, 8))}
          className="px-3 py-1 text-xs rounded border border-neutral-700 bg-neutral-900/80 backdrop-blur hover:bg-neutral-800"
        >
          +
        </button>
        <button
          type="button"
          onClick={() => setScale((s) => clamp(s / 1.5, 0.05, 8))}
          className="px-3 py-1 text-xs rounded border border-neutral-700 bg-neutral-900/80 backdrop-blur hover:bg-neutral-800"
        >
          −
        </button>
      </div>
      <div className="absolute bottom-3 right-3 text-xs text-neutral-500 font-mono">
        zoom {scale.toFixed(2)}× · {data.projects.length} project
        {data.projects.length === 1 ? "" : "s"}
      </div>
    </div>
  );
}

// ----- subcomponents -----------------------------------------------------

function ProjectThread({
  project,
  y,
  now,
  xForTime,
  detail,
  showLabel,
  showFeatureLabels,
  scale,
  onLabelClick,
}: {
  project: Project;
  y: number;
  now: number;
  xForTime: (t: number) => number;
  detail?: ProjectDetail;
  showLabel: boolean;
  showFeatureLabels: boolean;
  scale: number;
  onLabelClick: () => void;
}) {
  const xStart = xForTime(project.created_at);
  const xEnd = xForTime(now);

  // counter-scale labels so text doesn't grow with zoom
  const labelScale = 1 / scale;

  return (
    <Group>
      {/* Glow underlay */}
      <Line
        points={[xStart, y, xEnd, y]}
        stroke={project.color}
        strokeWidth={priorityStrokeWidth(project.priority) + 6}
        opacity={0.12}
        lineCap="round"
        listening={false}
      />
      {/* Main thread */}
      <Line
        points={[xStart, y, xEnd, y]}
        stroke={project.color}
        strokeWidth={priorityStrokeWidth(project.priority)}
        opacity={0.85}
        lineCap="round"
        listening={false}
      />

      {/* Project label */}
      {showLabel && (
        <Group
          x={xStart}
          y={y - 22}
          scaleX={labelScale}
          scaleY={labelScale}
          onClick={onLabelClick}
          onTap={onLabelClick}
        >
          <Rect
            x={-4}
            y={-2}
            width={Math.max(project.name.length * 8 + 12, 60)}
            height={20}
            fill="#0a0a0a"
            stroke={project.color}
            strokeWidth={1}
            cornerRadius={3}
            opacity={0.9}
          />
          <Text
            text={project.name}
            x={4}
            y={2}
            fontSize={13}
            fontFamily="ui-sans-serif, system-ui"
            fill="#e5e5e5"
          />
        </Group>
      )}

      {/* Feature orbs */}
      {detail?.features.map((f) => (
        <FeatureOrb
          key={f.id}
          feature={f}
          y={y}
          xForTime={xForTime}
          showLabel={showFeatureLabels}
          labelScale={labelScale}
        />
      )) ?? null}
    </Group>
  );
}

function FeatureOrb({
  feature,
  y,
  xForTime,
  showLabel,
  labelScale,
}: {
  feature: Feature;
  y: number;
  xForTime: (t: number) => number;
  showLabel: boolean;
  labelScale: number;
}) {
  const xCreated = xForTime(feature.created_at);
  const xCompleted =
    feature.completed_at != null ? xForTime(feature.completed_at) : null;
  const color = STATUS_COLORS[feature.status];

  return (
    <Group>
      {/* Connector line from created → completed if both exist */}
      {xCompleted != null && (
        <Line
          points={[xCreated, y, xCompleted, y]}
          stroke={color}
          strokeWidth={1.5}
          opacity={0.5}
          listening={false}
        />
      )}

      {/* Created orb */}
      <Circle
        x={xCreated}
        y={y}
        radius={ORB_RADIUS}
        stroke={color}
        strokeWidth={1.5}
        fill={feature.status === "done" ? color : "transparent"}
        opacity={feature.status === "dropped" ? 0.4 : 0.95}
      />

      {/* Completed orb (filled) */}
      {xCompleted != null && (
        <Circle
          x={xCompleted}
          y={y}
          radius={ORB_RADIUS}
          fill={color}
          opacity={0.95}
        />
      )}

      {/* Title */}
      {showLabel && (
        <Group
          x={xCreated + 10}
          y={y - 6}
          scaleX={labelScale}
          scaleY={labelScale}
          listening={false}
        >
          <Text
            text={feature.title}
            fontSize={11}
            fontFamily="ui-sans-serif, system-ui"
            fill="#a3a3a3"
          />
        </Group>
      )}
    </Group>
  );
}

function NowLine({
  x,
  yTop,
  yBottom,
}: {
  x: number;
  yTop: number;
  yBottom: number;
}) {
  return (
    <Group listening={false}>
      <Line
        points={[x, yTop, x, yBottom]}
        stroke="#7aa2f7"
        strokeWidth={1.2}
        opacity={0.6}
        dash={[4, 4]}
      />
      <Circle x={x} y={yTop} radius={3} fill="#7aa2f7" opacity={0.8} />
    </Group>
  );
}

function BackgroundGrid({
  width,
  height,
  scale,
  offset,
}: {
  width: number;
  height: number;
  scale: number;
  offset: { x: number; y: number };
}) {
  // Faint grid in screen space — converted into world coordinates so it
  // moves with pan/zoom but stays at fixed visual density.
  const visibleLeft = -offset.x / scale;
  const visibleTop = -offset.y / scale;
  const visibleRight = visibleLeft + width / scale;
  const visibleBottom = visibleTop + height / scale;

  // Grid step in world units, chosen so screen-space step ~ 80px
  const desiredScreenStep = 80;
  const worldStep = niceStep(desiredScreenStep / scale);

  const lines: JSX.Element[] = [];
  let i = 0;
  for (
    let x = Math.floor(visibleLeft / worldStep) * worldStep;
    x < visibleRight;
    x += worldStep, i++
  ) {
    lines.push(
      <Line
        key={`v${i}`}
        points={[x, visibleTop, x, visibleBottom]}
        stroke="#262626"
        strokeWidth={1 / scale}
      />,
    );
  }
  let j = 0;
  for (
    let y = Math.floor(visibleTop / worldStep) * worldStep;
    y < visibleBottom;
    y += worldStep, j++
  ) {
    lines.push(
      <Line
        key={`h${j}`}
        points={[visibleLeft, y, visibleRight, y]}
        stroke="#262626"
        strokeWidth={1 / scale}
      />,
    );
  }
  return <>{lines}</>;
}

// ----- helpers -----------------------------------------------------------

function clamp(v: number, lo: number, hi: number) {
  return Math.max(lo, Math.min(hi, v));
}

function priorityStrokeWidth(priority: string): number {
  if (priority === "high") return 4;
  if (priority === "low") return 1.5;
  return 2.5;
}

// Pick a "nice" round step (1, 2, 5, 10, 20, 50…) closest to the target.
function niceStep(target: number): number {
  if (target <= 0) return 1;
  const exp = Math.floor(Math.log10(target));
  const base = Math.pow(10, exp);
  const norm = target / base;
  let nice;
  if (norm < 1.5) nice = 1;
  else if (norm < 3) nice = 2;
  else if (norm < 7) nice = 5;
  else nice = 10;
  return nice * base;
}

