          fill={color}
          opacity={0.95}
        />
      )}

      {/* Title */}
      {showLabel && (
        <Group
          x={xCreated + 10}
          y={y - 6}
          scaleX={labelScale}
          scaleY={labelScale}
          listening={false}
        >
          <Text
            text={feature.title}
            fontSize={11}
            fontFamily="ui-sans-serif, system-ui"
            fill="#a3a3a3"
          />
        </Group>
      )}
    </Group>
  );
}

function NowLine({
  x,
  yTop,
  yBottom,
}: {
  x: number;
  yTop: number;
  yBottom: number;
}) {
  return (
    <Group listening={false}>
      <Line
        points={[x, yTop, x, yBottom]}
        stroke="#7aa2f7"
        strokeWidth={1.2}
        opacity={0.6}
        dash={[4, 4]}
      />
      <Circle x={x} y={yTop} radius={3} fill="#7aa2f7" opacity={0.8} />
    </Group>
  );
}

function BackgroundGrid({
  width,
  height,
  scale,
  offset,
}: {
  width: number;
  height: number;
  scale: number;
  offset: { x: number; y: number };
