        stroke="#262626"
        strokeWidth={1 / scale}
      />,
    );
  }
  let j = 0;
  for (
    let y = Math.floor(visibleTop / worldStep) * worldStep;
    y < visibleBottom;
    y += worldStep, j++
  ) {
    lines.push(
      <Line
        key={`h${j}`}
        points={[visibleLeft, y, visibleRight, y]}
        stroke="#262626"
        strokeWidth={1 / scale}
      />,
    );
  }
  return <>{lines}</>;
}

// ----- helpers -----------------------------------------------------------

function clamp(v: number, lo: number, hi: number) {
  return Math.max(lo, Math.min(hi, v));
}

function priorityStrokeWidth(priority: string): number {
  if (priority === "high") return 4;
  if (priority === "low") return 1.5;
  return 2.5;
}

// Pick a "nice" round step (1, 2, 5, 10, 20, 50…) closest to the target.
function niceStep(target: number): number {
  if (target <= 0) return 1;
