1	// Package db owns the SQLite connection, embedded migrations, and the
2	// one-shot bootstrap seed. Everything that talks to the database goes
3	// through the *sql.DB exposed by Open.
4	package db
5	
6	import (
7		"database/sql"
8		"embed"
9		"fmt"
10		"io/fs"
11		"log"
12		"sort"
13		"strings"
14	
15		_ "modernc.org/sqlite"
16	)
17	
18	//go:embed migrations/*.sql
19	var migrationsFS embed.FS
20	
21	//go:embed seed.sql
22	var seedSQL string
23	
24	// Open creates the SQLite connection at path, runs all pending schema
25	// migrations, and — if the projects table is still empty afterwards —
26	// loads the bootstrap seed. Returns the open *sql.DB on success; the
27	// caller owns closing it.
28	//
29	// Connection string flags: WAL journaling for concurrent reads during
30	// SSE fan-out, foreign keys ON (they're off by default in SQLite), and
31	// busy_timeout so a long write doesn't blow up concurrent readers.
32	func Open(path string) (*sql.DB, error) {
33		dsn := fmt.Sprintf(
34			"file:%s?_pragma=journal_mode(WAL)&_pragma=foreign_keys(1)&_pragma=busy_timeout(5000)",
35			path,
36		)
37		conn, err := sql.Open("sqlite", dsn)
38		if err != nil {
39			return nil, fmt.Errorf("open sqlite: %w", err)
40		}
41		// The modernc driver is fine with multiple connections but WAL
42		// plus a single-user workload means we don't need a huge pool.
43		conn.SetMaxOpenConns(4)
44		conn.SetMaxIdleConns(2)
45	
46		if err := conn.Ping(); err != nil {
47			conn.Close()
48			return nil, fmt.Errorf("ping sqlite: %w", err)
49		}
50	
51		if err := migrate(conn); err != nil {
52			conn.Close()
53			return nil, fmt.Errorf("migrate: %w", err)
54		}
55	
56		if err := maybeSeed(conn); err != nil {
57			conn.Close()
58			return nil, fmt.Errorf("seed: %w", err)
59		}
60	
61		return conn, nil
62	}
63	
64	// migrate applies every SQL file under migrations/ whose numeric prefix
65	// is greater than the highest applied version recorded in schema_version.
66	// The schema_version table is created on first run if it doesn't exist.
67	func migrate(conn *sql.DB) error {
68		_, err := conn.Exec(`CREATE TABLE IF NOT EXISTS schema_version (
69			version INTEGER PRIMARY KEY
70		)`)
71		if err != nil {
72			return err
73		}
74	
75		var current int
76		if err := conn.QueryRow(
77			`SELECT COALESCE(MAX(version), 0) FROM schema_version`,
78		).Scan(&current); err != nil {
79			return err
80		}
81	
82		entries, err := fs.ReadDir(migrationsFS, "migrations")
83		if err != nil {
84			return err
85		}
86		names := make([]string, 0, len(entries))
87		for _, e := range entries {
88			if !e.IsDir() && strings.HasSuffix(e.Name(), ".sql") {
89				names = append(names, e.Name())
90			}
91		}
92		sort.Strings(names)
93	
94		for _, name := range names {
95			version := parseVersion(name)
96			if version == 0 {
97				log.Printf("db: skipping unparseable migration %q", name)
98				continue
99			}
100			if version <= current {
101				continue
102			}
103			body, err := fs.ReadFile(migrationsFS, "migrations/"+name)
104			if err != nil {
105				return fmt.Errorf("read %s: %w", name, err)
106			}
107			log.Printf("db: applying migration %s", name)
108			tx, err := conn.Begin()
109			if err != nil {
110				return err
111			}
112			if _, err := tx.Exec(string(body)); err != nil {
113				tx.Rollback()
114				return fmt.Errorf("apply %s: %w", name, err)
115			}
116			if _, err := tx.Exec(
117				`INSERT INTO schema_version(version) VALUES (?)`, version,
118			); err != nil {
119				tx.Rollback()
120				return fmt.Errorf("record %s: %w", name, err)
121			}
122			if err := tx.Commit(); err != nil {
123				return err
124			}
125		}
126		return nil
127	}
128	
129	// parseVersion pulls the numeric prefix off a migration filename
130	// ("0001_init.sql" → 1). Returns 0 if the name doesn't start with digits.
131	func parseVersion(name string) int {
132		var v int
133		for _, ch := range name {
134			if ch < '0' || ch > '9' {
135				break
136			}
137			v = v*10 + int(ch-'0')
138		}
139		return v
140	}
141	
142	// maybeSeed runs seed.sql if and only if the projects table is empty.
143	// This gives petboard its origin story — on a fresh install the very
144	// first project that exists is petboard itself.
145	func maybeSeed(conn *sql.DB) error {
146		var n int
147		if err := conn.QueryRow(`SELECT COUNT(*) FROM projects`).Scan(&n); err != nil {
148			return err
149		}
150		if n > 0 {
151			return nil
152		}
153		log.Printf("db: empty projects table — loading bootstrap seed")
154		if _, err := conn.Exec(seedSQL); err != nil {
155			return fmt.Errorf("exec seed: %w", err)
156		}
157		return nil
158	}
