package main

import (
	"context"
	"errors"
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"path/filepath"
	"strconv"
	"strings"
	"syscall"
	"time"

	"petboard/api"
	"petboard/db"
	"petboard/events"
	"petboard/mcp"
	"petboard/oauth"
	"petboard/service"
