// --- migrate -----------------------------------------------------------

func runMigrate(args []string) {
	fs := flag.NewFlagSet("migrate", flag.ExitOnError)
	dbPath := fs.String("db", envString("PETBOARD_DB", "/var/lib/petboard/petboard.db"), "SQLite path")
	_ = fs.Parse(args)

	conn, err := db.Open(*dbPath)
	if err != nil {
		log.Fatalf("petboard: open db: %v", err)
	}
	conn.Close()
	log.Printf("petboard: migrations applied")
}

// --- import-git --------------------------------------------------------

// runImportGit reads a git repository's commit history, groups commits
// into "work sessions" (commits within 30 minutes of each other count
// as one session), and inserts one effort_log row per session under
// the named project. Idempotency is left to the caller — running it
// twice will create duplicate effort entries.
//
// Heuristic for session minutes:
//
//   single-commit session  → 15 min credit (the "I sat down, did one
//                            thing, walked away" baseline)
//   multi-commit session   → (last - first) + 15 min buffer
//
// 15 minutes is chosen because the average git commit cadence isn't
// continuous typing — there's read time, debug time, doc time —
// 15 mins covers the lead-in to the first visible commit.
func runImportGit(args []string) {
	fs := flag.NewFlagSet("import-git", flag.ExitOnError)
	dbPath := fs.String("db", envString("PETBOARD_DB", "/var/lib/petboard/petboard.db"), "SQLite path")
	slug := fs.String("slug", "", "petboard project slug to log effort against")
	repo := fs.String("repo", "", "path to a local git repository")
	author := fs.String("author", "", "git author email to filter on (default: include all authors)")
	since := fs.String("since", "30 days ago", "git --since= argument (e.g. '2026-01-01' or '60 days ago')")
	dryRun := fs.Bool("dry-run", false, "print what would be logged without writing to the database")
	gapMins := fs.Int("gap-mins", 30, "commits more than this many minutes apart start a new session")
	_ = fs.Parse(args)

	if *slug == "" || *repo == "" {
		fmt.Fprintln(os.Stderr, "petboard import-git: --slug and --repo are required")
		fmt.Fprintln(os.Stderr, "  petboard import-git --slug=foo --repo=/path/to/repo [--author=me@example.com] [--since='30 days ago'] [--dry-run]")
		os.Exit(2)
	}

	// Build the git log command. Output one ISO timestamp per line so
	// the parsing is trivial. --no-merges keeps merge commits from
	// inflating session counts.
	gitArgs := []string{"-C", *repo, "log", "--no-merges", "--format=%cI",
		"--since=" + *since}
	if *author != "" {
		gitArgs = append(gitArgs, "--author="+*author)
	}
	out, err := exec.Command("git", gitArgs...).Output()
	if err != nil {
		log.Fatalf("petboard import-git: git log failed: %v", err)
	}

	var stamps []time.Time
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		t, err := time.Parse(time.RFC3339, line)
		if err != nil {
			log.Printf("petboard import-git: skipping unparseable commit time %q", line)
			continue
		}
		stamps = append(stamps, t)
	}
	if len(stamps) == 0 {
		log.Printf("petboard import-git: no commits matched")
		return
	}
	// git log returns newest-first; sort oldest-first for sessionization.
	sort.Slice(stamps, func(i, j int) bool { return stamps[i].Before(stamps[j]) })

	gap := time.Duration(*gapMins) * time.Minute
	type session struct {
		start, end time.Time
		count      int
	}
	var sessions []session
	cur := session{start: stamps[0], end: stamps[0], count: 1}
	for i := 1; i < len(stamps); i++ {
		if stamps[i].Sub(cur.end) > gap {
			sessions = append(sessions, cur)
			cur = session{start: stamps[i], end: stamps[i], count: 1}
		} else {
			cur.end = stamps[i]
			cur.count++
		}
	}
	sessions = append(sessions, cur)

	// Apply (or print) each session.
	if *dryRun {
		fmt.Printf("petboard import-git: %d sessions across %d commits (dry-run)\n", len(sessions), len(stamps))
	}

	var conn *sql.DB
	var svc *service.Service
	if !*dryRun {
		c, err := db.Open(*dbPath)
		if err != nil {
			log.Fatalf("petboard import-git: open db: %v", err)
		}
		defer c.Close()
		conn = c
		svc = service.New(conn)
	}

	totalMins := 0
	for _, sess := range sessions {
		// minutes credit
		mins := int64(15)
		if sess.count > 1 {
			d := sess.end.Sub(sess.start)
			mins = int64(d.Minutes()) + 15
		}
		totalMins += int(mins)

		note := fmt.Sprintf("git: %d commit(s) in %s",
			sess.count, sess.end.Sub(sess.start).Round(time.Minute))

		if *dryRun {
			fmt.Printf("  %s  +%dm  (%s)\n",
				sess.start.Format("2006-01-02 15:04"), mins, note)
			continue
		}
		if _, err := svc.LogEffort(*slug, service.LogEffortInput{
			Minutes: mins,
			Note:    &note,
		}); err != nil {
			log.Fatalf("petboard import-git: log_effort: %v", err)
		}
	}
	fmt.Printf("petboard import-git: %d sessions, %d minutes total\n", len(sessions), totalMins)
}

